class ProductionLogger {
  static final ProductionLogger _instance = ProductionLogger._internal();
  factory ProductionLogger() => _instance;
  ProductionLogger._internal();

  final bool _isProduction = kReleaseMode;
  final List<String> _logBuffer = [];
  final int _maxBufferSize = 1000;

  void _log(String level, String category, String message, [Map<String, dynamic>? data]) {
    if (_isProduction) {
      final sanitizedMessage = _sanitizeMessage(message);
      final sanitizedData = data != null ? _sanitizeData(data) : null;
      
      final logEntry = {
        'timestamp': DateTime.now().toIso8601String(),
        'level': level,
        'category': category,
        'message': sanitizedMessage,
        if (sanitizedData != null) 'data': sanitizedData,
      };
      
      _addToBuffer(jsonEncode(logEntry));
    } else {
      debugPrint('[$level][$category] $message ${data != null ? jsonEncode(data) : ''}');
    }
  }

  String _sanitizeMessage(String message) {
    return message
        .replaceAllMapped(RegExp(r'password["\s:=]+([^,}\s\]]+)', caseSensitive: false), 
            (match) => 'password: ***REDACTED***')
        .replaceAllMapped(RegExp(r'token["\s:=]+([^,}\s\]]+)', caseSensitive: false), 
            (match) => 'token: ***REDACTED***')
        .replaceAllMapped(RegExp(r'apikey["\s:=]+([^,}\s\]]+)', caseSensitive: false), 
            (match) => 'apikey: ***REDACTED***')
        .replaceAllMapped(RegExp(r'secret["\s:=]+([^,}\s\]]+)', caseSensitive: false), 
            (match) => 'secret: ***REDACTED***')
        .replaceAllMapped(RegExp(r'authorization["\s:=]+([^,}\s\]]+)', caseSensitive: false), 
            (match) => 'authorization: ***REDACTED***');
  }

  Map<String, dynamic> _sanitizeData(Map<String, dynamic> data) {
    final sanitized = <String, dynamic>{};
    
    data.forEach((key, value) {
      final lowerKey = key.toLowerCase();
      if (lowerKey.contains('password') || 
          lowerKey.contains('token') || 
          lowerKey.contains('secret') ||
          lowerKey.contains('apikey') ||
          lowerKey.contains('authorization')) {
        sanitized[key] = '***REDACTED***';
      } else if (value is Map<String, dynamic>) {
        sanitized[key] = _sanitizeData(value);
      } else if (value is List) {
        sanitized[key] = value.map((item) => 
          item is Map<String, dynamic> ? _sanitizeData(item) : item
        ).toList();
      } else {
        sanitized[key] = value;
      }
    });
    
    return sanitized;
  }

  void _addToBuffer(String entry) {
    _logBuffer.add(entry);
    if (_logBuffer.length > _maxBufferSize) {
      _logBuffer.removeAt(0);
    }
  }

  void logHttpRequest(String url, String method, Map<String, String>? headers, dynamic body) {
    _log('INFO', 'HTTP_REQUEST', 'Request: $method $url', {
      'url': url,
      'method': method,
      'headers': headers ?? {},
      'body': body,
