  void logDatabaseOperation(String operation, String table, Map<String, dynamic>? data) {
    _log('INFO', 'DATABASE', 'DB Operation: $operation on $table', {
      'operation': operation,
      'table': table,
      'data': data ?? {},
    });
  }

  void logAuth(String action, String? userId, Map<String, dynamic>? details) {
    _log('INFO', 'AUTH', 'Auth: $action', {
      'action': action,
      'userId': userId ?? 'unknown',
      'details': details ?? {},
    });
