class LoggingHttpClient extends http.BaseClient {
  final http.Client _inner;
  final ProductionLogger _logger = ProductionLogger();

  LoggingHttpClient(this._inner);

  @override
  Future<http.StreamedResponse> send(http.BaseRequest request) async {
    final body = request is http.Request ? request.body : 'Stream body';
    
    _logger.logHttpRequest(
      request.url.toString(),
      request.method,
      request.headers,
      body,
    );

    try {
      final response = await _inner.send(request);
      final responseBody = await response.stream.toBytes();
      final bodyString = utf8.decode(responseBody);

      _logger.logHttpResponse(
        request.url.toString(),
        response.statusCode,
        response.headers,
        bodyString,
      );

      return http.StreamedResponse(
        http.ByteStream.fromBytes(responseBody),
        response.statusCode,
        headers: response.headers,
        isRedirect: response.isRedirect,
        persistentConnection: response.persistentConnection,
        reasonPhrase: response.reasonPhrase,
        request: response.request,
      );
    } catch (e, stackTrace) {
      _logger.logError('HTTP_CLIENT', 'Request failed', e, stackTrace);
      rethrow;
    }
  }
}

class DatabaseLogger {
  final ProductionLogger _logger = ProductionLogger();

  Future<T> logOperation<T>(String operation, String table, Future<T> Function() callback, [Map<String, dynamic>? data]) async {
    _logger.logDatabaseOperation(operation, table, data);
    
    try {
      final result = await callback();
      _logger.logDatabaseOperation('${operation}_SUCCESS', table, {'result': result.toString()});
      return result;
    } catch (e, stackTrace) {
      _logger.logError('DATABASE', 'Operation failed: $operation on $table', e, stackTrace);
      rethrow;
    }
  }

  Future<T> insert<T>(String table, Map<String, dynamic> data, Future<T> Function() callback) {
    return logOperation('INSERT', table, callback, data);
  }

  Future<T> update<T>(String table, Map<String, dynamic> data, Future<T> Function() callback) {
    return logOperation('UPDATE', table, callback, data);
  }

  Future<T> delete<T>(String table, Map<String, dynamic> where, Future<T> Function() callback) {
    return logOperation('DELETE', table, callback, where);
  }

  Future<T> query<T>(String table, Map<String, dynamic>? params, Future<T> Function() callback) {
    return logOperation('QUERY', table, callback, params);
  }
}

